SET FOREIGN_KEY_CHECKS = 1;

-- =============================================
-- VERIFY
-- =============================================
SELECT 'service_user' as tbl, COUNT(*) as total FROM service_user
UNION ALL SELECT 'service_sellerprofile',  COUNT(*) FROM service_sellerprofile
UNION ALL SELECT 'service_buyertasks',     COUNT(*) FROM service_buyertasks
UNION ALL SELECT 'service_jobshistory',    COUNT(*) FROM service_jobshistory
UNION ALL SELECT 'service_sellerbehaviorlog', COUNT(*) FROM service_sellerbehaviorlog;

-- Shared devices (should show bot_device_A/B/C):
SELECT device_id, COUNT(DISTINCT seller_id) AS sellers
FROM service_sellerbehaviorlog GROUP BY device_id HAVING sellers > 1;

-- Shared IPs:
SELECT ip_address, COUNT(DISTINCT seller_id) AS sellers
FROM service_sellerbehaviorlog GROUP BY ip_address HAVING sellers > 1;

-- Duplicate screenshots:
SELECT proofSha256, COUNT(*) AS times_used
FROM service_jobshistory WHERE proofSha256 != ''
GROUP BY proofSha256 HAVING times_used > 1;